async () => {
  const teams = await codemode.Linear_list_teams({});
  const allStatuses = new Map();

  for (const team of teams) {
    const statuses = await codemode.Linear_list_issue_statuses({ team: team.id });
    for (const status of statuses) {
      if (!allStatuses.has(status.name)) {
        allStatuses.set(status.name, status.type);
      }
    }
  }

  return Array.from(allStatuses, ([name, type]) => ({ name, type }));
}

